+
+pub fn Parser(comptime T: type, comptime callback: ?fn(self: T) anyerror!void) type {
+	return struct {
+		const Self = @This();
+		pub const Args = T;
+
+		pub fn parse(allocator: NeverFailingAllocator, args: []const u8) !ParseResult(T) {
